[ExtensionOf(classStr(FormLetterContract))]
final class FormLetterContract_KPMGCommon_Extension
{
    public NoYes           KPMGCommon_PrintFormLetterPackingList,
                           KPMGCommon_PrintFormLetterWayBill, KPMGCommon_PrintDeclarationOfConformityCert, KPMGCommon_GroupProductLines;
    #define.CurrentVersion(1)
    #LOCALMACRO.CurrentList
        KPMGCommon_PrintFormLetterPackingList
        ,KPMGCommon_PrintFormLetterWayBill
        ,KPMGCommon_PrintDeclarationOfConformityCert
        ,KPMGCommon_GroupProductLines
    #ENDMACRO


}

Method.Source:
public container pack()
{

    container packedClass = next pack();
    return SysPackExtensions::appendExtension(packedClass, classStr(FormLetterContract_KPMGCommon_Extension), this.myPack());
}

private boolean myUnpack(container packedClass)
{
    Integer version = RunBase::getVersion(packedClass);
    switch (version)
    {
        case #CurrentVersion:
            [version, #CurrentList] = packedClass;
            break;
        default:
            return false;
    }
    return true;
}

public boolean unpack(container _packedClass)
{
    boolean result = next unpack(_packedClass);

    if (result)
    {
        container axmState = SysPackExtensions::findExtension(_packedClass, classStr(FormLetterContract_KPMGCommon_Extension));
        //Also unpack the extension
        if (!this.myUnpack(axmState))
        {
            result = false;
        }
    }

    return result;
}

